// ===== Helper Functions =====
function h1(text) {
  return new Paragraph({
    children: [new TextRun({ text, bold: true, size: 32, color: '1F4E79' })],
    spacing: { before: 400, after: 200 },
    heading: HeadingLevel.HEADING_1
  });
}
function h2(text) {
  return new Paragraph({
    children: [new TextRun({ text, bold: true, size: 28, color: '2E75B6' })],
    spacing: { before: 300, after: 150 },
    heading: HeadingLevel.HEADING_2
  });
}
function h3(text) {
  return new Paragraph({
    children: [new TextRun({ text, bold: true, size: 24, color: '333333' })],
    spacing: { before: 200, after: 100 },
    heading: HeadingLevel.HEADING_3
  });
}
function p(text) {
  return new Paragraph({
    children: [new TextRun({ text, size: 21 })],
    spacing: { after: 120 }
  });
}
function pb(text) {
  return new Paragraph({
    children: [new TextRun({ text, bold: true, size: 21 })],
    spacing: { after: 120 }
  });
}
function pi(text) {
  return new Paragraph({
    children: [new TextRun({ text, italics: true, size: 21, color: '2E75B6' })],
    spacing: { after: 120, left: 400 }
  });
}
function hr() {
  return new Paragraph({
    children: [new TextRun({ text: '─'.repeat(50), color: 'CCCCCC', size: 16 })],
    spacing: { before: 200, after: 200 }
  });
}

function makeTable(headers, rows) {
  const headerRow = new TableRow({
    tableHeader: true,
    children: headers.map(h => new TableCell({
      children: [new Paragraph({ children: [new TextRun({ text: h, bold: true, size: 18, color: 'FFFFFF' })] })],
      shading: { type: ShadingType.SOLID, color: '1F4E79' },
      width: { size: 9000 / headers.length, type: WidthType.DXA }
    }))
  });
  const dataRows = rows.map(row => new TableRow({
    children: row.map(cell => new TableCell({
      children: [new Paragraph({ children: [new TextRun({ text: String(cell), size: 18 })] })],
      width: { size: 9000 / headers.length, type: WidthType.DXA }
    }))
  }));
  return new Table({ rows: [headerRow, ...dataRows], width: { size: 9000, type: WidthType.DXA } });
}

