function h1(t) { return new Paragraph({ children: [new TextRun({ text: t, bold: true, size: 32, color: '1F4E79' })], spacing: { before: 360, after: 180 }, heading: HeadingLevel.HEADING_1 }); }
function h2(t) { return new Paragraph({ children: [new TextRun({ text: t, bold: true, size: 26, color: '2E75B6' })], spacing: { before: 280, after: 120 }, heading: HeadingLevel.HEADING_2 }); }
function h3(t) { return new Paragraph({ children: [new TextRun({ text: t, bold: true, size: 22, color: '404040' })], spacing: { before: 180, after: 80 } }); }
function p(t) { return new Paragraph({ children: [new TextRun({ text: t, size: 20 })], spacing: { after: 100 } }); }
function pb(t) { return new Paragraph({ children: [new TextRun({ text: t, bold: true, size: 20 })], spacing: { after: 100 } }); }
function pi(t) { return new Paragraph({ children: [new TextRun({ text: t, italics: true, size: 20, color: '2E75B6' })], spacing: { after: 100, left: 360 } }); }
function pr(t) { return new Paragraph({ children: [new TextRun({ text: t, size: 20, color: 'CC0000' })], spacing: { after: 80 } }); }
function hr() { return new Paragraph({ children: [new TextRun({ text: '─'.repeat(50), color: 'CCCCCC', size: 14 })], spacing: { before: 160, after: 160 } }); }

function tbl(headers, rows) {
  const hRow = new TableRow({ tableHeader: true, children: headers.map(h => new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: h, bold: true, size: 16, color: 'FFFFFF' })] })], shading: { type: ShadingType.SOLID, color: '1F4E79' } })) });
  const dRows = rows.map(row => new TableRow({ children: row.map(c => new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: String(c), size: 16 })] })] })) }));
